class Solution {
public:
    bool reorderedPowerOf2(int n) {
        string s = to_string(n);
        sort(s.begin(), s.end());
        int len = s.length();

        int power = 1;
        while (true) {
            string current = to_string(power);
            if (current.length() > len) {
                break;
            }
            if (current.length() == len) {
                string temp = current;
                sort(temp.begin(), temp.end());
                if (temp == s) {
                    return true;
                }
            }
            power *= 2;
        }
        return false;
    }
};

